import{_ as l,o as i,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-09（週六）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-09.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-09.md"}'),e={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-09.md"};function o(n,t,d,s,h,u){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="🫘-黃豆追蹤日報-—-2026-05-09-週六" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-09（週六） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-09-週六" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-09（週六）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-09 05:00 TST（2026-05-08 21:00 UTC） 報告類型：每日追蹤 CBOT 期貨時段說明：05:00 TST = 17:00 ET（前日），黃豆期貨處於 14:00-20:00 ET 休息時段</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>月漲跌</th><th>年漲跌</th><th>查詢時間</th></tr></thead><tbody><tr><td>CBOT 黃豆 7月 (ZSN26)</td><td>$11.96½/蒲式耳</td><td>+4¼¢</td><td>—</td><td>—</td><td>2026-05-08 09:07 CT</td></tr><tr><td>CBOT 黃豆 5月 (ZSK26)</td><td>1,194.50¢/蒲式耳</td><td>+17.50¢（+1.49%）</td><td>—</td><td>—</td><td>2026-05-08 13:17 EDT</td></tr><tr><td>黃豆粕 5月 (SMK26)</td><td>$321.00/噸</td><td>-$0.30（-0.09%）</td><td>—</td><td>—</td><td>2026-05-07 結算</td></tr><tr><td>WTI 原油</td><td>$95.42/桶</td><td>+0.64%</td><td>—</td><td>—</td><td>2026-05-08</td></tr></tbody></table><blockquote><p>來源：Successful Farming (2026-05-08)、Yahoo Finance (2026-05-08)、MarketWatch (2026-05-07)</p></blockquote><hr><h2 id="🔍-敘事延續-美伊-mou-到期-wasde-下週一" tabindex="-1">🔍 敘事延續：美伊 MoU 到期 + WASDE 下週一 <a class="header-anchor" href="#🔍-敘事延續-美伊-mou-到期-wasde-下週一" aria-label="Permalink to &quot;🔍 敘事延續：美伊 MoU 到期 + WASDE 下週一&quot;">​</a></h2><p>昨日（5/8）Trump 宣稱伊朗已同意放棄核武，但 Hormuz 海峽仍有交火。48 小時通牒已過，伊朗尚未正式回覆。</p><p><strong>關鍵轉折</strong>：</p><ul><li>原油從 $96.31 小幅回落至 $95.42，市場對 MoU 簽署仍有一定預期</li><li>黃豆 5 月合約 +1.49% 反彈，7 月合約也上漲</li><li><strong>5/12 WASDE</strong> 將首次公布 2026/27 作物年度預估 → 市場等待明確方向</li><li>黃豆粕前日飆漲 $14.20 後今日小回 $0.30，高位整理</li></ul><p><strong>情境更新（延續昨日）</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">情境</th><th style="text-align:right;">機率</th><th style="text-align:left;">CBOT 黃豆預期</th><th>傳導機制</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>MoU 簽署</strong></td><td style="text-align:right;">50-55%</td><td style="text-align:left;">$10.50-11.50</td><td>原油跌 → 生柴利潤崩 → 豆油降溫 → 黃豆回跌</td></tr><tr><td style="text-align:left;"><strong>協議破裂</strong></td><td style="text-align:right;">40-45%</td><td style="text-align:left;">$12.50-14.00</td><td>原油續飆 → 生柴爆衝 → 壓榨利潤創新高</td></tr><tr><td style="text-align:left;"><strong>僵持延續</strong></td><td style="text-align:right;">&lt;15%</td><td style="text-align:left;">$11.50-12.50</td><td>中性延續，靜待 5/12 WASDE</td></tr></tbody></table><blockquote><p><strong>下一個關鍵時間</strong>：5/12（一）USDA WASDE、5/14（三）川習會</p></blockquote><hr><h2 id="🔍-8-項追蹤指標" tabindex="-1">🔍 8 項追蹤指標 <a class="header-anchor" href="#🔍-8-項追蹤指標" aria-label="Permalink to &quot;🔍 8 項追蹤指標&quot;">​</a></h2><h3 id="_1-🌱-usda-種植進度報告-每週" tabindex="-1">1. 🌱 USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-🌱-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. 🌱 USDA 種植進度報告（每週）&quot;">​</a></h3><p><strong>⚠️ 維持前次數據 — 下次更新 5/12（WASDE 同日）</strong></p><ul><li>前次（5/3）：全美黃豆種植 <strong>33%</strong>，超前五年平均 23%</li><li>各州：路易斯安那 84%、密西西比 77%、阿肯色 73%</li><li>北部平原有低溫霜凍風險</li><li><strong>變化</strong>：無重大變化，等待 5/12 WASDE 更新</li><li>來源：USDA/DTN (2026-05-04)</li></ul><h3 id="_2-🇧🇷-巴西供應-每月" tabindex="-1">2. 🇧🇷 巴西供應（每月） <a class="header-anchor" href="#_2-🇧🇷-巴西供應-每月" aria-label="Permalink to &quot;2. 🇧🇷 巴西供應（每月）&quot;">​</a></h3><p><strong>⚠️ 延續前次數據</strong></p><ul><li>StoneX 上修巴西 2025/26 產量至 <strong>1.816 億噸</strong>（歷史紀錄）</li><li>收割進度 ~88.1%</li><li><strong>5/12 WASDE</strong> 預估巴西產量 180-181.6M 噸</li><li>阿根廷面積預估 +5%</li><li><strong>變化</strong>：無重大變化，等待 WASDE 確認</li><li>來源：StoneX/Ukragroconsult (2026-05-01)、DTN (2026-05-08)</li></ul><h3 id="_3-🧪-尿素價格-每月" tabindex="-1">3. 🧪 尿素價格（每月） <a class="header-anchor" href="#_3-🧪-尿素價格-每月" aria-label="Permalink to &quot;3. 🧪 尿素價格（每月）&quot;">​</a></h3><p><strong>⚠️ 延續前次數據</strong></p><ul><li>尿素 $616.25/噸（5/6 單日 +6.71%，月跌 12.96%）</li><li>世界銀行預測 2026 全球尿素價格可能飆漲 60%</li><li><strong>變化</strong>：無重大變化</li><li>來源：TradingEconomics (2026-05-06)</li></ul><h3 id="_4-🚢-荷莫茲海峽通航-即時-🔥" tabindex="-1">4. 🚢 荷莫茲海峽通航（即時）🔥 <a class="header-anchor" href="#_4-🚢-荷莫茲海峽通航-即時-🔥" aria-label="Permalink to &quot;4. 🚢 荷莫茲海峽通航（即時）🔥&quot;">​</a></h3><p><strong>🔴 高度不確定 — 交火持續，NACHO 策略成共識</strong></p><ul><li>5/7 夜：美伊在 Hormuz 交火，互相指控對方先開火</li><li>Trump 稱「停火仍在」，稱攻擊為「愛的輕拍」</li><li>華爾街 NACHO 策略：「Not A Chance Hormuz Opens」— 市場對快速重開失去信心</li><li><strong>影響</strong>：若海峽重開 → 能源成本暴跌 → 生柴需求降溫 → 黃豆壓力；若破局 → 原油續飆 → 生柴需求衝刺</li><li><strong>變化</strong>：🔴 交火升級 + NACHO 共識形成</li><li>來源：CNBC (2026-05-08)、Al Jazeera (2026-05-08)</li></ul><h3 id="_5-🇺🇸🇨🇳-中美貿易-每月" tabindex="-1">5. 🇺🇸🇨🇳 中美貿易（每月） <a class="header-anchor" href="#_5-🇺🇸🇨🇳-中美貿易-每月" aria-label="Permalink to &quot;5. 🇺🇸🇨🇳 中美貿易（每月）&quot;">​</a></h3><p><strong>⚠️ 延續前次數據 — 等待 5/14 川習會</strong></p><ul><li>舊作出口銷售：僅 520 萬蒲式耳（行銷年度低）</li><li>中國仍為最大買家，但因價格和政治因素聚焦巴西豆</li><li>5/14 川習會可能討論貿易議題</li><li><strong>變化</strong>：無重大變化，等待川習會</li><li>來源：Brownfield Ag News (2026-05-08)</li></ul><h3 id="_6-🛢️-天然氣價格-每月" tabindex="-1">6. 🛢️ 天然氣價格（每月） <a class="header-anchor" href="#_6-🛢️-天然氣價格-每月" aria-label="Permalink to &quot;6. 🛢️ 天然氣價格（每月）&quot;">​</a></h3><p><strong>⚠️ 延續前次數據</strong></p><ul><li>Henry Hub $2.78/MMBtu（+1.92%）</li><li>EIA 庫存注入低於預期</li><li><strong>變化</strong>：無重大變化</li><li>來源：TradingEconomics (2026-05-07)</li></ul><h3 id="_7-🌡️-聖嬰-拉尼娜-每季" tabindex="-1">7. 🌡️ 聖嬰/拉尼娜（每季） <a class="header-anchor" href="#_7-🌡️-聖嬰-拉尼娜-每季" aria-label="Permalink to &quot;7. 🌡️ 聖嬰/拉尼娜（每季）&quot;">​</a></h3><p><strong>⚠️ 延續前次分析</strong></p><ul><li>全球氣候正從拉尼娜過渡至聖嬰，預計 2026 年中形成</li><li>部分預測警告「超級聖嬰」可能性</li><li><strong>對黃豆</strong>：聖嬰通常有利全球產量 +2%~5%（美國中西部、巴西南部涼爽潮濕）</li><li>DTN：聖嬰模式對美國黃豆有利，但目前種植進度超前，缺乏投機催化劑</li><li><strong>變化</strong>：DTN 確認聖嬰有利，但無新催化劑</li><li>來源：NOAA/CPC (2026-05)、DTN (2026-05-08)</li></ul><h3 id="_8-📈-cbot-價格區間-每日" tabindex="-1">8. 📈 CBOT 價格區間（每日） <a class="header-anchor" href="#_8-📈-cbot-價格區間-每日" aria-label="Permalink to &quot;8. 📈 CBOT 價格區間（每日）&quot;">​</a></h3><p><strong>🟡 小幅反彈 — 高位整理</strong></p><ul><li>5 月合約：1,194.50¢（+1.49%）</li><li>7 月合約：$11.96½（+4¼¢）</li><li>黃豆粕：$321.00（結算價，前日飆漲後小回）</li><li>近期區間：$11.50-12.00</li><li><strong>變化</strong>：🟡 反彈但仍在區間內</li><li>來源：Yahoo Finance (2026-05-08)、Successful Farming (2026-05-08)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><h3 id="_1-wasde-下週一公布首次-2026-作物預估" tabindex="-1">1. WASDE 下週一公布首次 2026 作物預估 <a class="header-anchor" href="#_1-wasde-下週一公布首次-2026-作物預估" aria-label="Permalink to &quot;1. WASDE 下週一公布首次 2026 作物預估&quot;">​</a></h3><ul><li>5/12 WASDE 將首次公布 2026/27 作物年度供應需求預估</li><li>巴西產量預估 180-181.6M 噸</li><li>阿根廷面積預估 +5%</li><li>市場等待明確方向</li><li>來源：DTN (2026-05-08)</li></ul><h3 id="_2-舊作出口銷售創行銷年度新低" tabindex="-1">2. 舊作出口銷售創行銷年度新低 <a class="header-anchor" href="#_2-舊作出口銷售創行銷年度新低" aria-label="Permalink to &quot;2. 舊作出口銷售創行銷年度新低&quot;">​</a></h3><ul><li>黃豆舊作出口僅 520 萬蒲式耳（行銷年最低）</li><li>中國持續轉向巴西豆</li><li>新作出口仍待觀察</li><li>來源：Brownfield Ag News (2026-05-08)</li></ul><h3 id="_3-黃豆粕高位整理-壓榨需求堅挺" tabindex="-1">3. 黃豆粕高位整理，壓榨需求堅挺 <a class="header-anchor" href="#_3-黃豆粕高位整理-壓榨需求堅挺" aria-label="Permalink to &quot;3. 黃豆粕高位整理，壓榨需求堅挺&quot;">​</a></h3><ul><li>黃豆粕結算 $321.00（前日飆漲 $14.20 後微回）</li><li>生物柴油政策 + 飼料需求雙重支撐</li><li>壓榨利潤仍處高位</li><li>來源：MarketWatch (2026-05-07)</li></ul><h3 id="_4-聖嬰有利黃豆-但缺乏投機催化劑" tabindex="-1">4. 聖嬰有利黃豆，但缺乏投機催化劑 <a class="header-anchor" href="#_4-聖嬰有利黃豆-但缺乏投機催化劑" aria-label="Permalink to &quot;4. 聖嬰有利黃豆，但缺乏投機催化劑&quot;">​</a></h3><ul><li>DTN：聖嬰模式對美國黃豆有利</li><li>目前種植進度超前，市場等待 WASDE</li><li>無明確投機催化劑</li><li>來源：DTN (2026-05-08)、BigGo Finance (2026-05-08)</li></ul><h3 id="_5-hormuz-交火持續-油價-95-支撐生柴需求" tabindex="-1">5. Hormuz 交火持續，油價 $95+ 支撐生柴需求 <a class="header-anchor" href="#_5-hormuz-交火持續-油價-95-支撐生柴需求" aria-label="Permalink to &quot;5. Hormuz 交火持續，油價 $95+ 支撐生柴需求&quot;">​</a></h3><ul><li>WTI $95.42（+0.64%），海峽交火維持油價高檔</li><li>若油價持續高位 → 生柴需求 → 豆油 → 黃豆支撐</li><li>NACHO 策略暗示短期內海峽不會重開</li><li>來源：CNBC (2026-05-08)、JPMorgan (2026-05-07)</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Successful Farming (2026-05-08): 7 月黃豆 $11.96½</li><li>Yahoo Finance (2026-05-08): 5 月黃豆 1,194.50¢</li><li>MarketWatch (2026-05-07): 黃豆粕 $321.00 結算</li><li>DTN (2026-05-08): WASDE 預告、聖嬰分析</li><li>Brownfield Ag News (2026-05-08): 出口銷售、Hormuz 影響</li><li>Al Jazeera (2026-05-08): 伊朗回覆進展</li><li>CNBC (2026-05-08): NACHO 策略、美伊交火</li><li>StoneX/Ukragroconsult (2026-05-01): 巴西產量 1.816 億噸</li><li>TradingEconomics (2026-05-06): 尿素 $616.25</li><li>NOAA/CPC (2026-05): 聖嬰預測</li></ol>',55)])])}const b=l(e,[["render",o]]);export{c as __pageData,b as default};
